const express = require('express');
const service = require('./service');

const router = express.Router();

router.get('/', (req, res) => {
  try {
    const projects = service.getAllProjects();
    res.json({ projects });
  } catch (error) {
    res.status(400).json({ error: { code: 'BAD_REQUEST', message: error.message } });
  }
});

router.post('/', (req, res) => {
  try {
    const project = service.createProject(req.body);
    res.status(201).json(project);
  } catch (error) {
    res.status(400).json({ error: { code: 'BAD_REQUEST', message: error.message } });
  }
});

router.get('/:id/tasks', (req, res) => {
  try {
    const tasks = service.getTasksByProjectId(req.params.id);
    res.json({ tasks });
  } catch (error) {
    res.status(404).json({ error: { code: 'NOT_FOUND', message: error.message } });
  }
});

module.exports = router;

const express = require('express');
const service = require('./service');

const router = express.Router();

router.post('/:projectId', (req, res) => {
  try {
    const task = service.createTask(req.params.projectId, req.body);
    res.status(201).json(task);
  } catch (error) {
    res.status(400).json({ error: { code: 'BAD_REQUEST', message: error.message } });
  }
});

router.patch('/:projectId/:taskId', (req, res) => {
  try {
    const task = service.updateTask(req.params.projectId, req.params.taskId, req.body);
    res.json(task);
  } catch (error) {
    res.status(404).json({ error: { code: 'NOT_FOUND', message: error.message } });
  }
});

router.get('/:projectId/:taskId/comments', (req, res) => {
  try {
    const comments = service.getCommentsByTaskId(req.params.projectId, req.params.taskId);
    res.json({ comments });
  } catch (error) {
    res.status(404).json({ error: { code: 'NOT_FOUND', message: error.message } });
  }
});

module.exports = router;

